//! WASM bindings for Flight Recorder.

use bitwarden_flight_recorder::{FlightRecorderEvent, flight_recorder_count, read_flight_recorder};
use wasm_bindgen::prelude::*;

// TypeScript type definition for the FlightRecorderClient class interface.
// Note: FlightRecorderEvent type is auto-generated by Tsify derivation.
// This custom section is only needed to define the class method signatures.
#[wasm_bindgen(typescript_custom_section)]
const TS_APPEND_CONTENT: &'static str = r#"
export interface FlightRecorderClient {
    read(): FlightRecorderEvent[];
    count(): number;
    inject_test_logs(count: number): void;
}
"#;

/// WASM client for Flight Recorder operations.
///
/// Note: This client does NOT wrap the main Client struct because
/// the Flight Recorder buffer is global (initialized in init_sdk),
/// not tied to a specific PasswordManagerClient instance.
#[wasm_bindgen]
pub struct FlightRecorderClient;

#[wasm_bindgen]
impl FlightRecorderClient {
    /// Create a new FlightRecorderClient.
    ///
    /// The buffer is global, so this is just a handle for WASM access.
    #[wasm_bindgen(constructor)]
    pub fn new() -> Self {
        Self
    }

    /// Read all events from the Flight Recorder buffer.
    ///
    /// Returns all events currently in the buffer. After calling this, the buffer is empty.
    /// Tsify handles WASM serialization automatically via VectorIntoWasmAbi.
    pub fn read(&self) -> Vec<FlightRecorderEvent> {
        read_flight_recorder()
    }

    /// Get current event count without draining.
    pub fn count(&self) -> usize {
        flight_recorder_count()
    }

    /// TEMPORARY: Inject test logs for eviction testing.
    /// Generates `count` INFO-level log events to test buffer behavior.
    pub fn inject_test_logs(&self, count: usize) {
        for i in 0..count {
            tracing::info!(test_index = i, "Test log for eviction testing");
        }
    }
}

impl Default for FlightRecorderClient {
    fn default() -> Self {
        Self::new()
    }
}
